INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05330', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '父母教養風格（Parenting styles）是影響嬰幼兒社會化的因子之一。目前已有大量研究，且有一致性的結 果與發現。下列對於父母教養風格的敘述，何者錯誤？', '["美國發展心理學家Diana Baumrind將父母教養風格區分為「溫暖」與「控制」兩個鑑別向度", "Barber（2002）認為父母的控制可分為行為控制（behavior control）及心理控制（psychological control）", "使用高心理控制或低溫暖教養風格的父母，可能是高風險群的父母", "家庭外部的經濟、文化或家庭結構等因素對於家庭及兒少產生影響，但因此使兒童落入弱勢的可能性 不高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05331', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '中途輟學為常見的青少年問題之一，下列對於中途輟學的敘述，何者錯誤？', '["生態系統模式認為中途輟學的發生可能因為個人問題或是家庭系統不平衡，或是與學校、同儕互動過 程經驗不良而產生的行為問題", "差別連結理論認為中輟學生犯罪行為主要是來自於遺傳基因與社會環境的互動所致", "社會控制理論認為中輟學生脫離主流文化，可能增強對同儕次文化的認同，進而接受同儕團體的價值 觀與信念", "中輟與學業挫敗、低成就及來自不利的社會階層呈現顯著相關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05332', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於青少年犯罪的理論敘述，何者錯誤？', '["機會理論認為低教育水平，逸樂奢侈成習的青少年會尋求不合法的機會而犯罪", "場域理論認為個人所屬的親密團體，例如家庭或同儕團體成員如有犯罪行為，個人也很容易學會犯罪", "犯罪次文化理論認為犯罪率高的社區，犯罪的價值觀點、態度及行為是代代相傳的，所以犯罪行為才 會互相傳播", "標籤理論認為個人偏差行為一旦被發現並公開指責，加上不良標籤後，會導致更嚴重的偏差行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05333', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於青春期自我或認同的理論敘述，何者錯誤？', '["佛洛伊德（Freud）強調青春期性徵期發展出具有生殖及性親密感能力的原慾", "艾瑞克森（Erikson）認為青春期階段是認同與角色混淆的階段", "柯柏格（Kohlberg）認為青春期是道德自律期，主要發展出超越個人所屬社會的道德原則", "皮亞傑（Piaget）認為青春期是具體運思階段，藉由具體事務發展出抽象問題構思能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05334', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於兒童中期階段性發展任務的敘述，下列何者錯誤？', '["佛洛依德（Freud）認為兒童中期的發展受到性本能衝動支配力增強", "皮亞傑（Piaget）認為兒童中期道德觀念的改變由絕對與外控演進為相對的道德觀以及內控的良知", "柯柏格（Kohlberg）認為兒童中期會依據外在懲罰或報酬來推理，並考量外界的意見", "艾瑞克森（Erikson）認為兒童中期的合作創新發展能力增長，引發稱職感或無能感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05335', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '個案家庭有夫妻及子女四位成員，夫妻兩人均就業且子女就讀國中。自從個案去年有了婚外情，且已同 居，夫妻關係轉壞，子女因為家庭缺乏溫暖，女兒開始有藥物濫用及婚前性行為。以上家庭問題較適合 採用那一個社會學理論進行解釋？', '["符號互動論（Symbolic Interactionism）", "衝突理論（Conflict Theory）", "系統理論（System Theory）", "場地理論（Field Theory）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05336', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於社會工作者協助婦女墮胎時所扮演的角色敘述，何者錯誤？', '["社會工作者作為談判者的角色，要求墮胎婦女之伴侶支付相關醫藥費用", "社會工作者作為使能者的角色，協助婦女確認妊娠中止時可能的選擇及評估正負面", "社會工作者作為教育者的角色，提供避孕諮詢以避免再次非預期懷孕", "社會工作者作為倡導者的角色，促使禁止墮胎政策及法令的修訂，使婦女得到需要的服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05337', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者並非「女性主義理論」（feminist theories）的主要概念？', '["Van Den Bergh與Cooper（1986）認為生物學將人區分為男性或女性二分法的方式應該被排除", "女性主義者強調性別角色社會化的影響", "女性主義者確信男女兩性生命經驗的差異", "「個人即政治」（The personal is political）的概念意指女性個人力量太過微小，很難影響政治環境裡的 性別歧視政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05338', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於街友的敘述，何者錯誤？', '["有家庭的人，不太可能成為街友的", "近年來低薪與失業率的衝擊，是造成街友成長的原因之一", "街友的組成很多元，異質性也很高", "職業訓練和擁有一技之長是促進街友就業機會的策略之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05339', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於單親家庭的敘述，何者正確？', '["相較於傳統家庭中長大的孩子，單親家庭中長大的孩子遭遇行為、社會、情緒或課業方面困擾的機會 是相同的", "Rutter（1983）指出，與其生活在一個親子關係良好的單親家庭，不如生活在氣氛不和諧的傳統家庭， 其發展情況較好", "Hetherington（1980）的研究指出，缺席的父親或母親對孩子所造成的傷害，甚至比一個冷漠無情的父 親或母親來的嚴重", "只有母親收入的單親家庭，因收入比傳統家庭來的少，其落入貧窮的風險較高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
